// Placeholder for MoviesRepositoryImpl.kt
package edu.dyds.movies.data

import edu.dyds.movies.data.external.RemoteMoviesDataSource
import edu.dyds.movies.data.local.LocalMoviesCache
import edu.dyds.movies.domain.entity.Movie
import edu.dyds.movies.domain.entity.QualifiedMovie
import edu.dyds.movies.domain.repository.MoviesRepository

private const val MIN_VOTE_AVERAGE = 6.0

class MoviesRepositoryImpl(
    private val remoteMoviesDataSource: RemoteMoviesDataSource,
    private val localMoviesCache: LocalMoviesCache
) : MoviesRepository {

    override suspend fun getPopularMovies(): List<QualifiedMovie> {
        val remoteMovies = localMoviesCache.getCachedMovies() ?: run {
            val fetched = remoteMoviesDataSource.getPopularMovies()
            localMoviesCache.saveMovies(fetched)
            fetched
        }
        return remoteMovies.sortAndMap()
    }

    override suspend fun getMovieDetails(id: Int): Movie? {
        return remoteMoviesDataSource.getMovieDetails(id)?.toDomainMovie()
    }

    private fun List<edu.dyds.movies.data.external.RemoteMovie>.sortAndMap(): List<QualifiedMovie> {
        return this
            .sortedByDescending { it.voteAverage }
            .map {
                QualifiedMovie(
                    movie = it.toDomainMovie(),
                    isGoodMovie = it.voteAverage >= MIN_VOTE_AVERAGE
                )
            }
    }
}

package edu.dyds.movies.data.external

interface RemoteMoviesDataSource {
}

package edu.dyds.movies.data.external

import kotlinx.serialization.SerialName
import kotlinx.serialization.Serializable

interface RemoteMoviesDataSource {
    suspend fun getPopularMovies(): List<RemoteMovie>
    suspend fun getMovieDetails(id: Int): RemoteMovie?
}

@Serializable
data class RemoteResult(
    val page: Int,
    val results: List<RemoteMovie>,
    @SerialName("total_pages") val totalPages: Int,
    @SerialName("total_results") val totalResults: Int
)

@Serializable
data class RemoteMovie(
    val id: Int,
    val title: String,
    val overview: String,
    @SerialName("release_date") val releaseDate: String,
    @SerialName("poster_path") val posterPath: String,
    @SerialName("backdrop_path") val backdropPath: String?,
    @SerialName("original_title") val originalTitle: String,
    @SerialName("original_language") val originalLanguage: String,
    val popularity: Double,
    @SerialName("vote_average") val voteAverage: Double,

    ) {
    fun toDomainMovie(): edu.dyds.movies.domain.entity.Movie {
        return edu.dyds.movies.domain.entity.Movie(
            id = id,
            title = title,
            overview = overview,
            releaseDate = releaseDate,
            poster = "https://image.tmdb.org/t/p/w185$posterPath",
            backdrop = backdropPath.let { "https://image.tmdb.org/t/p/w780$it" },
            originalTitle = originalTitle,
            originalLanguage = originalLanguage,
            popularity = popularity,
            voteAverage = voteAverage
        )
    }
}

package edu.dyds.movies.data.external

import io.ktor.client.HttpClient
import io.ktor.client.call.body
import io.ktor.client.request.get

class RemoteMoviesDataSourceImpl(private val httpClient: HttpClient) : RemoteMoviesDataSource {
    override suspend fun getPopularMovies(): List<RemoteMovie> {
        return try {
            httpClient.get("/3/discover/movie?sort_by=popularity.desc").body<RemoteResult>().results
        } catch (e: Exception) {
            emptyList()
        }
    }

    override suspend fun getMovieDetails(id: Int): RemoteMovie? {
        return try {
            httpClient.get("/3/movie/$id").body<RemoteMovie>()
        } catch (e: Exception) {
            null
        }
    }
}

package edu.dyds.movies.data.local
import edu.dyds.movies.data.external.RemoteMovie
interface LocalMoviesCache { fun getCachedMovies(): List<RemoteMovie>? fun saveMovies(movies: List<RemoteMovie>) fun clearCache() }

package edu.dyds.movies.data.local

import edu.dyds.movies.data.external.RemoteMovie

class LocalMoviesCacheImpl : LocalMoviesCache {
    private val cacheMovies: MutableList<RemoteMovie> = mutableListOf()

    override fun getCachedMovies(): List<RemoteMovie>? {
        return if (cacheMovies.isNotEmpty()) cacheMovies else null
    }

    override fun saveMovies(movies: List<RemoteMovie>) {
        cacheMovies.clear()
        cacheMovies.addAll(movies)
    }

    override fun clearCache() {
        cacheMovies.clear()
    }
}

