        resizable = false,
        onCloseRequest = { dialogState = false },
        visible = dialogState
    ) {
        Image(
            painter = painterResource("images/too_bad.png"),
            contentDescription = null,
            contentScale = ContentScale.Fit,
            modifier = Modifier
                .fillMaxWidth()
                .aspectRatio(1f)
        )
    }
}

